const now = new Date();

const start = new Date(now);
start.setDate(start.getDate() - 30);

const end = new Date(now);

function fmt(d) {
  return d.toISOString().slice(0, 10);
}

return [{
  json: {
    ...$json,
    start_date: fmt(start),
    end_date: fmt(end),
    month_label: `last_30_days_${fmt(start)}_bis_${fmt(end)}`
  }
}];

const items = $input.all();

let raw = items[0].json.data ?? items[0].json;

if (typeof raw === 'string') {
  raw = JSON.parse(raw);
}

if (raw.data && Array.isArray(raw.data)) {
  raw = raw.data;
}

if (!Array.isArray(raw)) {
  raw = [raw];
}

const expenses = [];

for (const entry of raw) {
  const attr = entry.attributes || {};
  const splits = attr.transactions || [];

  for (const tx of splits) {
    const amount = Number(tx.amount || 0);
    const txType = tx.type || attr.type || '';

    if (txType === 'withdrawal' || amount < 0) {
      expenses.push({
        id: entry.id,
        journal_id: tx.transaction_journal_id,

        date: tx.date || attr.date || attr.created_at || '',
        description: tx.description || attr.description || '',

        amount: Math.abs(amount),
        currency: tx.currency_code || attr.currency_code || 'EUR',

        source_id: tx.source_id || '',
        source: tx.source_name || '',
        destination_id: tx.destination_id || '',
        destination: tx.destination_name || '',

        category: tx.category_name || 'Unkategorisiert',
        type: txType
      });
    }
  }
}

const total = expenses.reduce((sum, e) => sum + Number(e.amount || 0), 0);

let month = 'Unbekannt';

try {
  month =
    $('Letzten Monat berechnen').first().json.month ||
    expenses[0]?.date?.slice(0, 7) ||
    'Unbekannt';
} catch (e) {
  month = expenses[0]?.date?.slice(0, 7) || 'Unbekannt';
}

return [
  {
    json: {
      month,
      total_expenses: total.toFixed(2),
      transaction_count: expenses.length,
      expenses
    }
  }
];

let text =
  $json.output?.[0]?.content?.[0]?.text ||
  $json.text ||
  $json.message ||
  $json.content ||
  '';

text = String(text)
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

const parsed = JSON.parse(text);

// Originaldaten aus dem Kategorien-Prompt holen
const original = $('Ausgaben kategorisieren').first().json.expenses || [];

return parsed.map(t => {
  const old = original.find(o => String(o.id) === String(t.id) && String(o.journal_id) === String(t.journal_id)) || {};

  return {
    json: {
      id: t.id,
      journal_id: t.journal_id,

      description: old.description || t.description,
      amount: old.amount,
      date: old.date,
      type: old.type,

      source_id: old.source_id,
      source_name: old.source,
      destination_id: old.destination_id,
      destination_name: old.destination,

      old_category: old.category || 'Unkategorisiert',
      new_category: t.new_category || t.category || 'Sonstiges'
    }
  };
});

const items = $input.all();

let raw = items[0].json.data ?? items[0].json;

// String → JSON
if (typeof raw === 'string') {
  raw = JSON.parse(raw);
}

if (raw.data && Array.isArray(raw.data)) {
  raw = raw.data;
}

if (!Array.isArray(raw)) {
  raw = [raw];
}

const categories = {};
let total = 0;

for (const entry of raw) {
  const attr = entry.attributes || {};
  const splits = attr.transactions || [];

  for (const tx of splits) {
    const amount = Number(tx.amount || 0);
    const category = tx.category_name || 'Unkategorisiert';

    if (amount < 0 || tx.type === 'withdrawal') {
      const abs = Math.abs(amount);

      total += abs;
      categories[category] = (categories[category] || 0) + abs;
    }
  }
}

// Sortieren
const sorted = Object.entries(categories)
  .sort((a, b) => b[1] - a[1])
  .map(([cat, val]) => ({
    category: cat,
    amount: val.toFixed(2)
  }));

return [
  {
    json: {
      total: total.toFixed(2),
      categories: sorted
    }
  }
];

